CREATE CACHED TABLE "PUBLIC"."ENCLOSURES"(
    "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 9) SELECTIVITY 100 NOT NULL,
    "NAME" CHARACTER VARYING(100) SELECTIVITY 100 NOT NULL,
    "HABITAT_TYPE" CHARACTER VARYING(50) SELECTIVITY 75 NOT NULL,
    "CLEANLINESS" DOUBLE PRECISION DEFAULT 100.0 SELECTIVITY 100 NOT NULL,
    "CAPACITY" INTEGER DEFAULT 10 SELECTIVITY 87 NOT NULL,
    "LAST_CLEANED" TIMESTAMP DEFAULT CURRENT_TIMESTAMP SELECTIVITY 12,
    "MAINTENANCE_SCHEDULE" CHARACTER VARYING(100) DEFAULT 'Daily' SELECTIVITY 25
);    
ALTER TABLE "PUBLIC"."ENCLOSURES" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_7" PRIMARY KEY("ID");   
