CREATE CACHED TABLE "PUBLIC"."ANIMALS"(
    "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 13) SELECTIVITY 100 NOT NULL,
    "NAME" CHARACTER VARYING(100) SELECTIVITY 100 NOT NULL,
    "SPECIES" CHARACTER VARYING(100) SELECTIVITY 91 NOT NULL,
    "TYPE" CHARACTER VARYING(20) SELECTIVITY 25 NOT NULL,
    "AGE" INTEGER SELECTIVITY 83 NOT NULL,
    "HEALTH" DOUBLE PRECISION DEFAULT 100.0 SELECTIVITY 75 NOT NULL,
    "HUNGER" DOUBLE PRECISION DEFAULT 0.0 SELECTIVITY 33 NOT NULL,
    "HYDRATION" DOUBLE PRECISION DEFAULT 100.0 SELECTIVITY 83 NOT NULL,
    "ACTIVITY_LEVEL" DOUBLE PRECISION DEFAULT 80.0 SELECTIVITY 75 NOT NULL,
    "ENCLOSURE_ID" INTEGER SELECTIVITY 58,
    "ASSIGNED_ZOOKEEPER" CHARACTER VARYING(100) SELECTIVITY 33,
    "ADMISSION_DATE" DATE SELECTIVITY 100,
    "HAS_FUR" BOOLEAN DEFAULT FALSE SELECTIVITY 16,
    "FUR_COLOR" CHARACTER VARYING(50) SELECTIVITY 33,
    "WINGSPAN_CM" DOUBLE PRECISION SELECTIVITY 33,
    "CAN_FLY" BOOLEAN DEFAULT TRUE SELECTIVITY 16,
    "IS_VENOMOUS" BOOLEAN DEFAULT FALSE SELECTIVITY 16,
    "UVB_REQUIREMENT" DOUBLE PRECISION DEFAULT 5.0 SELECTIVITY 33
);            
ALTER TABLE "PUBLIC"."ANIMALS" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_F" PRIMARY KEY("ID");      
